  if tok <> TK_ARROW then begin parse_error := true; exit end;
  lex_next;
  body := parse_expr;
  if parse_error then exit;
  first_arm := mk_arm(pat, body);
  first_arm^.extra := guard;
  prev_arm := first_arm;
